const fs = require\('fs'\);

// Minimal valid 1x1 PNG scaled — build a proper PNG programmatically
// Using pure Node.js to create a solid color PNG
function createSolidPNG\(width, height, r, g, b\) {
  const zlib = require\('zlib'\);

  // PNG signature
  const sig = Buffer.from\([137,80,78,71,13,10,26,10]\);

  // IHDR chunk
  function uint32\(n\) {
    const b = Buffer.alloc\(4\); b.writeUInt32BE\(n\); return b;
  }
  function crc32\(buf\) {
    let c = 0xFFFFFFFF;
    for \(let i = 0; i < buf.length; i++\) {
      c ^= buf[i];
      for \(let j = 0; j < 8; j++\) c = \(c & 1\) ? \(0xEDB88320 ^ \(c >>> 1\)\) : \(c >>> 1\);
    }
    return \(c ^ 0xFFFFFFFF\) >>> 0;
  }
  function chunk\(type, data\) {
    const t = Buffer.from\(type\);
    const len = uint32\(data.length\);
    const crcBuf = Buffer.concat\([t, data]\);
    return Buffer.concat\([len, t, data, uint32\(crc32\(crcBuf\)\)]\);
  }

  const ihdrData = Buffer.concat\([uint32\(width\), uint32\(height\), Buffer.from\([8,2,0,0,0]\)]\);
  const ihdr = chunk\('IHDR', ihdrData\);

  // Image data: each row = filter byte \(0\) + RGB pixels
  const row = Buffer.alloc\(1 + width * 3\);
  row[0] = 0; // filter none
  for \(let x = 0; x < width; x++\) { row[1+x*3]=r; row[2+x*3]=g; row[3+x*3]=b; }
  const raw = Buffer.concat\(Array\(height\).fill\(row\)\);
  const compressed = zlib.deflateSync\(raw, { level: 9 }\);
  const idat = chunk\('IDAT', compressed\);
  const iend = chunk\('IEND', Buffer.alloc\(0\)\);

  return Buffer.concat\([sig, ihdr, idat, iend]\);
}

// Tuscany gold: #B8914A = rgb\(184,145,74\)
const png192 = createSolidPNG\(192, 192, 184, 145, 74\);
const png512 = createSolidPNG\(512, 512, 184, 145, 74\);

fs.writeFileSync\('D:/Users/silvi/Documents/Hive/Clients/Tuscany/tuscany-storage/public/icons/icon-192.png', png192\);
fs.writeFileSync\('D:/Users/silvi/Documents/Hive/Clients/Tuscany/tuscany-storage/public/icons/icon-512.png', png512\);
console.log\('done'\);
")

