const mongoose = require\('mongoose'\)
mongoose.connect\('mongodb://localhost:27017/tuscany-storage'\).then\(async \(\) => {
  const db = mongoose.connection.db
  const tenant = await db.collection\('tenants'\).findOne\({ email: 'john@example.com' }\)
  console.log\('Tenant:', JSON.stringify\({ _id: tenant._id, name: tenant.firstName + ' ' + tenant.lastName }\)\)

  const payments = await db.collection\('payments'\).find\({ tenantId: tenant._id }\).toArray\(\)
  console.log\('Payments:', JSON.stringify\(payments.map\(p => \({ _id: p._id, amount: p.amount, status: p.status, type: p.type, createdAt: p.createdAt }\)\), null, 2\)\)

  const lease = await db.collection\('leases'\).findOne\({ tenantId: tenant._id, status: { \\$in: ['active', 'pending_moveout'] } }\)
  if \(lease\) {
    const unit = await db.collection\('units'\).findOne\({ _id: lease.unitId }\)
    console.log\('Lease:', JSON.stringify\({ _id: lease._id, monthlyRate: lease.monthlyRate, billingDay: lease.billingDay, status: lease.status }\)\)
    console.log\('Unit:', unit ? JSON.stringify\({ _id: unit._id, number: unit.number, name: unit.name }\) : 'NOT FOUND'\)
  } else {
    console.log\('No active lease'\)
  }
  await mongoose.disconnect\(\)
}\)")

