const mongoose = require\('mongoose'\)
mongoose.connect\('mongodb://localhost:27017/tuscany-storage'\).then\(async \(\) => {
  const db = mongoose.connection.db
  // Find units that are occupied but their lease has no signedAt
  const leases = await db.collection\('leases'\).find\({ status: 'active', signedAt: { \\$exists: false } }\).toArray\(\)
  console.log\('Unsigned active leases:', leases.map\(l => \({ id: l._id, unitId: l.unitId, tenantId: l.tenantId }\)\)\)
  for \(const lease of leases\) {
    const unit = await db.collection\('units'\).findOne\({ _id: lease.unitId }\)
    console.log\('Unit status:', unit?.unitNumber, unit?.status\)
    if \(unit?.status === 'occupied'\) {
      await db.collection\('units'\).updateOne\({ _id: unit._id }, { \\$set: { status: 'reserved' } }\)
      console.log\('Reset unit', unit.unitNumber, 'to reserved'\)
    }
  }
  await mongoose.disconnect\(\)
}\).catch\(e => console.error\(e\)\)")
